{
  "command": "duckdb '/Users/shreyashankar/Documents/projects/DataAgentBench/query_GITHUB_REPOS/query_dataset/repo_artifacts.db' \"SELECT COUNT(*) FROM contents WHERE sample_path = 'README.md' OR LOWER(sample_path) = 'readme.md';\"",
  "description": "Count README.md files"
}

{
  "command": "duckdb '/Users/shreyashankar/Documents/projects/DataAgentBench/query_GITHUB_REPOS/query_dataset/repo_artifacts.db' \"SELECT COUNT(*) FROM contents WHERE sample_path = 'README.md';\"",
  "description": "Count README.md files exact match"
}

{
  "command": "duckdb '/Users/shreyashankar/Documents/projects/DataAgentBench/query_GITHUB_REPOS/query_dataset/repo_artifacts.db' "ATTACH '/Users/shreyashankar/Documents/projects/DataAgentBench/query_GITHUB_REPOS/query_dataset/repo_metadata.db' AS meta (TYPE SQLITE); 
SELECT COUNT(*) AS total, 
       SUM(CASE WHEN LOWER(content) LIKE '%copyright%' THEN 1 ELSE 0 END) AS with_copyright
FROM contents c
JOIN meta.languages l ON c.sample_repo_name = l.repo_name
WHERE c.sample_path = 'README.md'
AND LOWER(l.language_description) NOT LIKE '%python%';"",
  "description": "Check proportion of README.md with copyright for non-Python repos"
}
